// ─── AI Terminal Preset Definitions ──────────────────────────────────────────
// Each preset defines a name, command to run, keyboard shortcut, and icon.

export interface AIPreset {
  id: string;
  label: string;
  command: string;
  shortcut: string; // display string e.g. "⌘ 1"
  shortcutKey: string; // the key to match in keydown e.g. "1"
  icon: React.ReactNode;
}

