// ─── Helpers ─────────────────────────────────────────────────────────────────

/** Given a command string stored on a tile, return the matching preset icon or default terminal */
export function getPresetIcon(
  initialCommand?: string,
  size = 16,
  tileType?: string,
): React.ReactNode {
  if (tileType === "browser") return <IconBrowser size={size} />;
  if (!initialCommand) return <IconDefaultTerminal size={size} />;
  const cmd = initialCommand.toLowerCase();
  if (cmd.includes("claude")) return <IconAnthropic size={size} />;
  if (cmd.includes("codex")) return <IconOpenAI size={size} />;
  if (cmd.includes("gemini")) return <IconGemini size={size} />;
  if (cmd.includes("opencode")) return <IconOpenCode size={size} />;
  if (cmd.includes("nvim")) return <IconNeovim size={size} />;
  if (cmd === "agent" || cmd.includes("cursor")) return <IconCursor size={size} />;
  if (cmd.includes("ollama")) return <IconOllama size={size} />;
  return <IconDefaultTerminal size={size} />;
}
